import { useState, useEffect } from "react";

function useWindowSize() {
  const [size, setSize] = useState({
    w: typeof window !== "undefined" ? window.innerWidth : 1200,
    h: typeof window !== "undefined" ? window.innerHeight : 800,
  });
  useEffect(() => {
    const handler = () => setSize({ w: window.innerWidth, h: window.innerHeight });
    window.addEventListener("resize", handler);
    return () => window.removeEventListener("resize", handler);
  }, []);
  return size;
}

const C = { black: "#000000", navy: "#14213D", amber: "#FCA311", silver: "#E5E5E5", white: "#FFFFFF", navyLight: "#1B2D4F", amberSoft: "rgba(252,163,17,0.10)", amberMuted: "rgba(252,163,17,0.6)", silverDark: "#CCCCCC", bg: "#F7F7F7", text1: "#14213D", text2: "#6B7280", text3: "#9CA3AF", danger: "#DC2626", dangerBg: "#FEE2E2", success: "#059669", successBg: "#D1FAE5", whatsapp: "#25D366" };
const F = "Helvetica, 'Helvetica Neue', sans-serif";
const R = { sm: 8, md: 12, lg: 16, xl: 24, pill: 999 };

function Box({ children, style }) { return <div style={{ background: C.white, borderRadius: R.md, padding: "10px 14px", marginBottom: 8, border: `1px solid ${C.silver}`, ...style }}>{children}</div>; }
function Btn({ children, primary, green, style, small }) { return <div style={{ background: green ? C.whatsapp : primary ? C.amber : C.silver, color: green || primary ? C.navy : C.text1, borderRadius: R.md, padding: small ? "8px 16px" : "13px 0", textAlign: "center", fontWeight: 700, fontSize: small ? 12 : 13, fontFamily: F, marginBottom: 8, cursor: "pointer", letterSpacing: 0.2, ...style }}>{children}</div>; }
