function Lbl({ children }) { return <div style={{ fontSize: 10, color: C.text2, marginBottom: 3, fontWeight: 700, letterSpacing: 0.8, textTransform: "uppercase", fontFamily: F }}>{children}</div>; }
function Hdr({ l, t, r }) { return <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", paddingBottom: 12, borderBottom: `1px solid ${C.silver}`, marginBottom: 16 }}><span style={{ fontSize: 12, color: C.text2, minWidth: 40, fontFamily: F }}>{l}</span><span style={{ fontWeight: 800, fontSize: 15, color: C.navy, fontFamily: F }}>{t}</span><span style={{ fontSize: 12, color: C.text2, minWidth: 40, textAlign: "right", fontFamily: F }}>{r}</span></div>; }
function Tab({ a = 0 }) { const items = [{ i: "🏠", l: "Home" }, { i: "🧭", l: "Explore" }, { i: "💰", l: "Wallet" }, { i: "👤", l: "Profile" }]; return <div style={{ display: "flex", borderTop: `1px solid ${C.silver}`, padding: "8px 0 6px", background: C.white }}>{items.map((t, i) => <div key={i} style={{ flex: 1, textAlign: "center", fontSize: 9, color: i === a ? C.navy : C.text3, fontWeight: i === a ? 800 : 500, fontFamily: F }}><div style={{ fontSize: 17, marginBottom: 1 }}>{t.i}</div>{t.l}{i === a && <div style={{ width: 4, height: 4, borderRadius: 4, background: C.amber, margin: "2px auto 0" }} />}</div>)}</div>; }
function Av({ s = 32, c = C.silver, style }) { return <div style={{ width: s, height: s, borderRadius: s, background: c, flexShrink: 0, ...style }} />; }
function Ch({ children, active }) { return <div style={{ display: "inline-block", padding: "6px 12px", borderRadius: R.pill, fontSize: 11, fontWeight: 600, background: active ? C.navy : C.bg, color: active ? C.amber : C.text1, fontFamily: F }}>{children}</div>; }
function Wrap({ children, style }) { return <div style={{ padding: 20, fontFamily: F, ...style }}>{children}</div>; }
function Shell({ children, tab = 0, noPad }) { return <div style={{ display: "flex", flexDirection: "column", height: "100%", fontFamily: F }}><div style={{ flex: 1, overflowY: "auto", padding: noPad ? 0 : 16 }}>{children}</div><Tab a={tab} /></div>; }
function Row2({ l, r }) { return <div style={{ display: "flex", justifyContent: "space-between", padding: "8px 0", borderBottom: `1px solid ${C.silver}` }}><span style={{ fontSize: 12, color: C.text2, fontFamily: F }}>{l}</span><span style={{ fontSize: 12, fontWeight: 700, color: C.navy, fontFamily: F }}>{r}</span></div>; }

