// ─── SCREEN MAP ───
const SCREENS = {
  splash:{name:"Splash",group:"Auth",desc:"App launch"},login:{name:"Login",group:"Auth",desc:"Phone entry"},otp:{name:"OTP Verify",group:"Auth",desc:"6-digit code"},profileSetup:{name:"Profile Setup",group:"Auth",desc:"Name & username"},gateway:{name:"Gateway",group:"Auth",desc:"Create or Join"},
  createStep1:{name:"Create: Name",group:"Pool Create",desc:"Name & type"},createStep2:{name:"Create: Schedule",group:"Pool Create",desc:"Duration & time"},createStep3:{name:"Create: Stakes",group:"Pool Create",desc:"Buy-in & rules"},createStep4:{name:"Create: Review",group:"Pool Create",desc:"Confirm"},shareInvite:{name:"Share Invite",group:"Pool Create",desc:"WhatsApp & QR"},
  joinCode:{name:"Enter Code",group:"Pool Join",desc:"Invite code"},joinConsent:{name:"Consent",group:"Pool Join",desc:"Rules & mandate"},joinPay:{name:"Payment",group:"Pool Join",desc:"Razorpay"},
  home:{name:"Home",group:"Dashboard",desc:"Pool cards"},poolDetail:{name:"Pool Detail",group:"Dashboard",desc:"Feed & pot"},leaderboard:{name:"Leaderboard",group:"Dashboard",desc:"Rankings"},
  camera:{name:"Camera",group:"Check-in",desc:"Take photo"},liveness:{name:"Liveness",group:"Check-in",desc:"Verification"},preview:{name:"Preview",group:"Check-in",desc:"Review & caption"},checkinSuccess:{name:"Success",group:"Check-in",desc:"Streak confirmed"},
  feed:{name:"Pool Feed",group:"Social",desc:"Check-ins"},wallOfShame:{name:"Wall of Shame",group:"Social",desc:"Miss & milestone"},reactions:{name:"Reactions",group:"Social",desc:"React picker"},
  wallet:{name:"Wallet",group:"Wallet",desc:"Balances"},ledger:{name:"Ledger",group:"Wallet",desc:"Transactions"},paymentMethods:{name:"Methods",group:"Wallet",desc:"UPI & cards"},
  profile:{name:"Profile",group:"Profile",desc:"Stats & badges"},badges:{name:"Badges",group:"Profile",desc:"Achievements"},settings:{name:"Settings",group:"Profile",desc:"Preferences"},
  explore:{name:"Explore",group:"Discover",desc:"Public pools"},powerups:{name:"Power-Ups",group:"Discover",desc:"Shop"},notifications:{name:"Notifications",group:"Discover",desc:"Alerts"},
  fineAlert:{name:"Fine Alert",group:"Overlays",desc:"Miss modal"},payoutSuccess:{name:"Payout!",group:"Overlays",desc:"Win celebration"},
};
const GROUPS = [...new Set(Object.values(SCREENS).map(s => s.group))];
const RENDERERS = {splash:SplashScreen,login:LoginScreen,otp:OTPScreen,profileSetup:ProfileSetupScreen,gateway:GatewayScreen,createStep1:CreateStep1,createStep2:CreateStep2,createStep3:CreateStep3,createStep4:CreateStep4,shareInvite:ShareInviteScreen,joinCode:JoinCodeScreen,joinConsent:JoinConsentScreen,joinPay:JoinPayScreen,home:HomeScreen,poolDetail:PoolDetailScreen,leaderboard:LeaderboardScreen,camera:CameraScreen,liveness:LivenessScreen,preview:PreviewScreen,checkinSuccess:CheckinSuccessScreen,feed:FeedScreen,wallOfShame:WallOfShameScreen,reactions:ReactionsScreen,wallet:WalletScreen,ledger:LedgerScreen,paymentMethods:PaymentMethodsScreen,profile:ProfileScreen,badges:BadgesScreen,settings:SettingsScreen,explore:ExploreScreen,powerups:PowerUpsScreen,notifications:NotificationsScreen,fineAlert:FineAlertScreen,payoutSuccess:PayoutSuccessScreen};

export default function App() {
  const [screen, setScreen] = useState("splash");
  const [group, setGroup] = useState("Auth");
  const [drawerOpen, setDrawerOpen] = useState(false);
  const { w: width, h: height } = useWindowSize();
  const isMobile = width < 640;

  const isDark = ["splash","camera","liveness","preview","checkinSuccess","payoutSuccess","fineAlert"].includes(screen);
  const Comp = RENDERERS[screen];

  const PHONE_W = 292;
  const PHONE_H = 600;

  // Space consumed by UI chrome (title/topbar + pills row + padding)
  // Desktop: 16pt + ~50title + 12gap + 28pills + 16pb = 122
  // Mobile: 64pt (topbar+gap) + 12gap + 28pills + 20pb = 124
  const vOverhead = isMobile ? 124 : 122;
  const hOverhead = isMobile ? 32 : 192 + 32; // sidebar + padding

  const scaleW = (width - hOverhead) / PHONE_W;
  const scaleH = (height - vOverhead) / PHONE_H;
  const scale = Math.min(1, scaleW, scaleH);
  const phoneW = Math.round(PHONE_W * scale);
  const phoneH = Math.round(PHONE_H * scale);

  const SidebarContent = () => (
    <>
      <div style={{ flex: 1, overflowY: "auto", padding: "0 6px" }}>
        {GROUPS.map(g => <div key={g} style={{ marginBottom: 2 }}>
          <div onClick={() => setGroup(g)} style={{ fontSize: 9, fontWeight: 700, color: group===g?C.amber:"rgba(255,255,255,0.3)", padding: "7px 6px 3px", cursor: "pointer", textTransform: "uppercase", letterSpacing: 1.2, fontFamily: F }}>{g}</div>
          {group===g && Object.entries(SCREENS).filter(([,v]) => v.group===g).map(([id,s]) => <div key={id} onClick={() => { setScreen(id); setDrawerOpen(false); }} style={{ padding: "5px 10px", borderRadius: 6, cursor: "pointer", fontSize: 11, fontWeight: screen===id?700:400, color: screen===id?C.amber:"rgba(255,255,255,0.5)", background: screen===id?C.amberSoft:"transparent", marginBottom: 1, fontFamily: F }}>{s.name}</div>)}
        </div>)}
      </div>
      <div style={{ padding: "6px 12px", borderTop: "1px solid rgba(255,255,255,0.06)", fontSize: 8, color: "rgba(255,255,255,0.18)", flexShrink: 0 }}>{Object.keys(SCREENS).length} screens · Helvetica</div>
    </>
  );

  return (
    <div style={{ display: "flex", height: "100vh", background: C.black, fontFamily: F, color: C.text1, overflow: "hidden" }}>

      {/* Desktop sidebar */}
      {!isMobile && (
        <div style={{ width: 192, background: C.navy, display: "flex", flexDirection: "column", flexShrink: 0, height: "100vh" }}>
          <div style={{ padding: "14px 12px 8px", flexShrink: 0 }}>
            <div style={{ fontSize: 20, fontWeight: 900, color: C.amber, fontFamily: F, letterSpacing: -1 }}>PoolUp</div>
            <div style={{ fontSize: 8, color: "rgba(255,255,255,0.3)", fontWeight: 600, letterSpacing: 1.5, marginTop: 2 }}>WIREFRAMES v2.0</div>
          </div>
          <SidebarContent />
        </div>
      )}

      {/* Mobile top bar */}
      {isMobile && (
        <div style={{ position: "fixed", top: 0, left: 0, right: 0, zIndex: 100, background: C.navy, display: "flex", alignItems: "center", justifyContent: "space-between", padding: "10px 16px", flexShrink: 0 }}>
          <div>
            <div style={{ fontSize: 18, fontWeight: 900, color: C.amber, fontFamily: F, letterSpacing: -0.5 }}>PoolUp</div>
            <div style={{ fontSize: 8, color: "rgba(255,255,255,0.3)", letterSpacing: 1.5 }}>WIREFRAMES v2.0</div>
          </div>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontSize: 11, fontWeight: 700, color: C.white, fontFamily: F }}>{SCREENS[screen].name}</div>
            <div style={{ fontSize: 9, color: "rgba(255,255,255,0.35)" }}>{SCREENS[screen].group}</div>
          </div>
          <div onClick={() => setDrawerOpen(true)} style={{ color: C.amber, fontSize: 22, cursor: "pointer", lineHeight: 1, marginLeft: 12 }}>☰</div>
        </div>
      )}

      {/* Mobile drawer overlay */}
      {isMobile && drawerOpen && (
        <div style={{ position: "fixed", inset: 0, zIndex: 200, background: "rgba(0,0,0,0.7)" }} onClick={() => setDrawerOpen(false)}>
          <div style={{ position: "absolute", left: 0, top: 0, bottom: 0, width: 240, background: C.navy, display: "flex", flexDirection: "column", overflow: "hidden" }} onClick={e => e.stopPropagation()}>
            <div style={{ padding: "14px 12px 8px", display: "flex", alignItems: "flex-start", justifyContent: "space-between", flexShrink: 0 }}>
              <div>
                <div style={{ fontSize: 20, fontWeight: 900, color: C.amber, fontFamily: F, letterSpacing: -1 }}>PoolUp</div>
                <div style={{ fontSize: 8, color: "rgba(255,255,255,0.3)", fontWeight: 600, letterSpacing: 1.5, marginTop: 2 }}>WIREFRAMES v2.0</div>
              </div>
              <div onClick={() => setDrawerOpen(false)} style={{ color: "rgba(255,255,255,0.5)", fontSize: 20, cursor: "pointer", lineHeight: 1, marginTop: 2 }}>✕</div>
            </div>
            <SidebarContent />
          </div>
        </div>
      )}

      {/* Center content — no scroll, everything fits */}
      <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: isMobile ? `${52 + 12}px 16px 20px` : 16, minWidth: 0, overflow: "hidden" }}>

        {!isMobile && (
          <div style={{ textAlign: "center", marginBottom: 12, flexShrink: 0 }}>
            <div style={{ fontSize: 17, fontWeight: 800, color: C.white, fontFamily: F }}>{SCREENS[screen].name}</div>
            <div style={{ fontSize: 10, color: "rgba(255,255,255,0.35)", marginTop: 2, fontFamily: F }}>{SCREENS[screen].group} → {SCREENS[screen].desc}</div>
          </div>
        )}

        {/* Phone mockup — outer box is the scaled visual size, inner div is full 292×600 scaled via CSS transform */}
        <div style={{ width: phoneW, height: phoneH, borderRadius: Math.round(34 * scale), overflow: "hidden", boxShadow: "0 0 0 3px #222, 0 0 60px rgba(252,163,17,0.06)", flexShrink: 0, position: "relative" }}>
          <div style={{ width: PHONE_W, height: PHONE_H, transform: `scale(${scale})`, transformOrigin: "top left" }}>
            <div style={{ height: 32, background: isDark?C.black:C.white, display: "flex", alignItems: "center", justifyContent: "space-between", padding: "0 18px", fontSize: 10, color: isDark?C.white:C.black, fontWeight: 600, fontFamily: F, position: "relative", zIndex: 2 }}>
              <span>9:41</span>
              <div style={{ width: 68, height: 18, background: C.black, borderRadius: 9, position: "absolute", left: "50%", transform: "translateX(-50%)", top: 5 }} />
              <span style={{ fontSize: 9 }}>📶 🔋</span>
            </div>
            <div style={{ height: PHONE_H - 32, background: isDark?C.black:C.white, overflowY: "auto", overflowX: "hidden" }}>{Comp && <Comp />}</div>
          </div>
        </div>

        {/* Screen quick-nav — single row, horizontally scrollable, fixed height */}
        <div style={{ display: "flex", gap: 4, marginTop: 12, flexShrink: 0, overflowX: "auto", width: "100%", justifyContent: "center", paddingBottom: 2 }}>
          {Object.entries(SCREENS).filter(([,v]) => v.group===group).map(([id,s]) => <div key={id} onClick={() => setScreen(id)} style={{ padding: "4px 10px", borderRadius: 6, fontSize: 10, cursor: "pointer", fontWeight: screen===id?700:400, background: screen===id?C.amber:"rgba(255,255,255,0.06)", color: screen===id?C.navy:"rgba(255,255,255,0.4)", fontFamily: F, whiteSpace: "nowrap", flexShrink: 0 }}>{s.name}</div>)}
        </div>
      </div>
    </div>
  );
}
